import os
from google.cloud import storage

def process_image(event, context):
    bucket_name = event['bucket']
    file_name = event['name']

    # Get the filename and extension from the file name
    filename, file_extension = os.path.splitext(file_name)

    # Define conversion options based on file type
    if file_extension == '.jpg' or file_extension == '.jpeg':
        convert_options = '-strip -quality 90'
    elif file_extension == '.png':
        convert_options = '-strip -quality 95'
    else:
        return "Unsupported image format"

    # Construct the command to run ImageMagick
    command = f"convert {convert_options} gs://{bucket_name}/{file_name} gs://{bucket_name}/processed/{filename}_processed{file_extension}"

    try:
        # Run the convert command using subprocess.call()
        process = subprocess.Popen(command, shell=True)
        process.wait()

        print(f"Image processed: {file_name}")
    except Exception as e:
        print(f"Error processing image: {e}")

